import{_ as r,y as s,a as i,o as a,ag as p,D as o,g as t,I as h}from"./chunks/framework.RVu0gECZ.js";const _=JSON.parse('{"title":"Truyền Dữ Liệu | Tải lên hàng loạt","description":"","frontmatter":{},"headers":[],"relativePath":"settings/data-transfer.md","filePath":"settings/data-transfer.md","lastUpdated":1775811487000}'),c={name:"settings/data-transfer.md"};function u(l,n,e,m,d,T){const g=s("ImagePopup");return a(),i("div",null,[n[0]||(n[0]=p('<h1 id="truyen-du-lieu-tai-len-hang-loat" tabindex="-1">Truyền Dữ Liệu | Tải lên hàng loạt <a class="header-anchor" href="#truyen-du-lieu-tai-len-hang-loat" aria-label="Permalink to &quot;Truyền Dữ Liệu | Tải lên hàng loạt&quot;">​</a></h1><p>Nhập số lượng lớn là tính năng cho phép người dùng nhập số lượng lớn dữ liệu vào hệ thống một cách nhanh chóng và hiệu quả.</p><p>Nó đơn giản hóa quy trình và tiết kiệm thời gian bằng cách không phải thêm từng thông tin một. Tính năng này hoạt động khác nhau đối với từng hệ thống và có nhiều trường hợp sử dụng khác nhau trên nhiều ngành cũng như VNS.</p><p>Bạn có thể dễ dàng Tải lên hàng loạt <strong>Sản phẩm, Khách hàng &amp; Thuế suất</strong>.</p><h3 id="cac-buoc-them-nhap-so-luong-lon-vao-vns" tabindex="-1">Các bước thêm Nhập số lượng lớn vào VNS <a class="header-anchor" href="#cac-buoc-them-nhap-so-luong-lon-vao-vns" aria-label="Permalink to &quot;Các bước thêm Nhập số lượng lớn vào VNS&quot;">​</a></h3><p><strong>Bước 1:</strong> Vào bảng quản trị của VNS nhấp vào <strong>Cài đặt &gt;&gt; Truyền dữ liệu</strong> và nhấp vào nút <strong>Tạo nhập</strong>.</p>',6)),o(g,{src:"/images/settings/import.png",alt:"Import"}),n[1]||(n[1]=p("<p><strong>Bước 2:</strong> Trong phần cấu hình chung, chọn các trường bên dưới:</p><p><strong>1) Loại –</strong> Vui lòng chọn loại tức là (Sản phẩm, Khách hàng, Thuế suất) mà bạn muốn nhập.</p><p><strong>2) Tệp –</strong> Chọn tệp ở định dạng bạn muốn (CSV, XLS, XLSX) và vui lòng đảm bảo rằng bạn có tất cả các trường bắt buộc trong tệp.</p><p><em>Lưu ý – Trong khi nhập dữ liệu sản phẩm, bạn có thể nhập các loại sản phẩm Đơn giản, Có thể cấu hình, Ảo, Theo gói &amp; Nhóm ngoại trừ các sản phẩm có thể tải xuống.</em></p><p><strong>3) Tải xuống mẫu –</strong> Bạn cũng có thể tải xuống các tệp mẫu thuộc các loại (Sản phẩm, Khách hàng, Thuế suất). Vui lòng đảm bảo rằng tệp bạn đang tải lên giống với tệp mẫu này.</p><p><strong>4) Đường dẫn thư mục hình ảnh –</strong> Sử dụng đường dẫn tương đối đến /project-root/storage/import/app, ví dụ: hình ảnh sản phẩm, hình ảnh nhập khẩu.</p><p><strong>5) Hành động –</strong> Vui lòng chọn từ cấu hình cài đặt mà bạn muốn Tạo/Cập nhật hoặc Xóa bản ghi.</p><p><strong>6) Chiến lược xác thực –</strong> Tính năng độc đáo này cho phép bạn Bỏ qua lỗi hoặc Dừng lỗi khi nhập dữ liệu.</p><p><strong>7) Lỗi được phép –</strong> Tính năng này cho phép bạn biết số lượng lỗi sẽ bị bỏ qua khi nhập dữ liệu.</p><p><strong>8) Dấu tách trường –</strong> Tính năng này cho phép bạn đặt các trường.</p><p><strong>9) Quy trình trong hàng đợi –</strong> Tính năng này cho phép bạn chạy quy trình nhập của mình trong hàng đợi.</p><p>Vì vậy bây giờ hãy nhấp vào nút <strong>Save Import</strong>.</p>",12)),o(g,{src:"/images/settings/createImport.png",alt:"Import"}),n[2]||(n[2]=t("p",null,[t("strong",null,"Bước 3:"),h(" Bây giờ quá trình nhập sẽ bắt đầu và sau khi hoàn tất, quá trình nhập sản phẩm sẽ được thực hiện.")],-1)),o(g,{src:"/images/settings/importDone.png",alt:"Import"}),n[3]||(n[3]=t("p",null,[t("strong",null,"Bước 4:"),h(" Bây giờ bạn sẽ có thể xem tất cả các sản phẩm trong phần "),t("strong",null,"Danh mục >>Sản phẩm"),h(" như trong hình ảnh nhất định.")],-1)),o(g,{src:"/images/settings/importOutput.png",alt:"Import"}),n[4]||(n[4]=t("p",null,[h("Bằng các bước trên, bạn có thể dễ dàng tạo "),t("strong",null,"Nhập hàng loạt"),h(" trong VNS.")],-1))])}const v=r(c,[["render",u]]);export{_ as __pageData,v as default};
